import scala.collection.mutable.PriorityQueue

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
  val rows = m.toInt
  val cols = n.toInt
  val dist = Array.ofDim[Long](rows, cols, 2)
  for (i <- 0 until rows; j <- 0 until cols) {
    dist(i)(j)(0) = Long.MaxValue
    dist(i)(j)(1) = Long.MaxValue
  }
  val entryCost = (0 + 1) * (0 + 1)
  dist(0)(0)(0) = entryCost
  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq.enqueue((entryCost, 0, 0, 0))
  val directions = Array((0, 1), (1, 0))

  while (pq.nonEmpty) {
    val (currentCost, i, j, p) = pq.dequeue()
    if (currentCost > dist(i)(j)(p)) continue
    if (i == rows - 1 && j == cols - 1) return currentCost
    if (p == 0) {
      for ((dx, dy) <- directions) {
        val ni = i + dx
        val nj = j + dy
        if (ni < rows && nj < cols) {
          val newCost = currentCost + ((ni + 1) * (nj + 1))
          if (newCost < dist(ni)(nj)(1)) {
            dist(ni)(nj)(1) = newCost
            pq.enqueue((newCost, ni, nj, 1))
          }
        }
      }
    } else {
      val newCost = currentCost + waitCost(i)(j)
      if (newCost < dist(i)(j)(0)) {
        dist(i)(j)(0) = newCost
        pq.enqueue((newCost, i, j, 0))
      }
    }
  }
  Long.MaxValue
}
