import scala.collection.mutable.PriorityQueue
import scala.collection.mutable.HashMap

def solve(m: Long, n: Long, waitCost: Array[Array[Long]]): Long = {
  val rows = m.toInt
  val cols = n.toInt
  val dest = (rows - 1, cols - 1)

  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq.enqueue(1, 0, 0, 1)

  val visited = HashMap[(Int, Int, Int), Long]()
  visited((0, 0, 1)) = 1

  while (pq.nonEmpty) {
    val (currentCost, i, j, time) = pq.dequeue()

    if (i == dest._1 && j == dest._2) {
      return currentCost
    }

    if (time % 2 == 1) {
      if (j + 1 < cols) {
        val newI = i
        val newJ = j + 1
        val newTime = time + 1
        val newCost = currentCost + (newI + 1) * (newJ + 1)
        val key = (newI, newJ, newTime)
        if (visited.getOrElse(key, Long.MaxValue) > newCost) {
          visited(key) = newCost
          pq.enqueue(newCost, newI, newJ, newTime)
        }
      }
      if (i + 1 < rows) {
        val newI = i + 1
        val newJ = j
        val newTime = time + 1
        val newCost = currentCost + (newI + 1) * (newJ + 1)
        val key = (newI, newJ, newTime)
        if (visited.getOrElse(key, Long.MaxValue) > newCost) {
          visited(key) = newCost
          pq.enqueue(newCost, newI, newJ, newTime)
        }
      }
    } else {
      val newTime = time + 1
      val newCost = currentCost + waitCost(i)(j)
      val key = (i, j, newTime)
      if (visited.getOrElse(key, Long.MaxValue) > newCost) {
        visited(key) = newCost
        pq.enqueue(newCost, i, j, newTime)
      }
    }
  }

  -1
}
